public SDAST forLet(Let l) {
  Def[] defs = l.defs();
  int n = defs.length;
  SDAST[] newRhs = new SDAST[n];
  for (int i = 0; i < n; i++) {
    symbolTable.put(defs[i].lhs(), new SDPair(depth+1,i));
    newRhs[i] = defs[i].rhs().accept(new SConvert(depth + 1));
  }
  SDAST result = new SLet(newRhs, l.body().accept(new SConvert(depth+1)));
  for (int i = 0; i < n; i++) symbolTable.remove(defs[n - 1 - i].lhs());
  return result;
}

